'use client'

import { useState } from 'react'
import { useRouter, usePathname } from 'next/navigation'
import { ConfigProvider, Layout, Menu, Button, Typography, Dropdown, Avatar, theme as antTheme } from 'antd'
import {
    DashboardOutlined,
    TeamOutlined,
    ProjectOutlined,
    FileTextOutlined,
    BookOutlined,
    ExperimentOutlined,
    MenuFoldOutlined,
    MenuUnfoldOutlined,
    SettingOutlined,
    SunOutlined,
    MoonOutlined,
    LogoutOutlined,
    UserOutlined,
} from '@ant-design/icons'
import { useSession, signOut } from '@/lib/auth-client'

const { Sider, Content, Header } = Layout
const { Text } = Typography

type ThemeMode = 'light' | 'dark'

export default function DashboardLayout({ children }: { children: React.ReactNode }) {
    const [collapsed, setCollapsed] = useState(false)
    const [themeMode, setThemeMode] = useState<ThemeMode>('light')
    const router = useRouter()
    const pathname = usePathname()
    const { data: session, isPending } = useSession()

    if (isPending) return null

    if (!session?.user) {
        router.push('/login')
        return null
    }

    const menuItems = [
        { key: '/dashboard', icon: <DashboardOutlined />, label: 'Dashboard' },
        { key: '/dashboard/teams', icon: <TeamOutlined />, label: 'Teams' },
        { key: '/dashboard/projects', icon: <ProjectOutlined />, label: 'Projects' },
        { key: '/dashboard/notes', icon: <FileTextOutlined />, label: 'Notes' },
        { key: '/dashboard/stories', icon: <BookOutlined />, label: 'Stories' },
        { key: '/dashboard/tests', icon: <ExperimentOutlined />, label: 'Tests' },
    ]

    const handleLogout = async () => {
        await signOut()
        router.push('/login')
    }

    const userMenuItems = [
        {
            key: 'profile',
            icon: <UserOutlined />,
            label: session.user.name || session.user.email,
            disabled: true,
        },
        { type: 'divider' as const },
        {
            key: 'logout',
            icon: <LogoutOutlined />,
            label: '退出登录',
            danger: true,
            onClick: handleLogout,
        },
    ]

    const antdTheme = {
        algorithm: themeMode === 'dark' ? antTheme.darkAlgorithm : antTheme.defaultAlgorithm,
        token: {
            borderRadius: 8,
            colorPrimary: '#1677ff',
            fontFamily: 'var(--font-sans)',
        },
        cssVar: { prefix: 'ockham' },
    }

    return (
        <ConfigProvider theme={antdTheme}>
            <Layout style={{ minHeight: '100vh' }}>
                <Sider
                    collapsible
                    collapsed={collapsed}
                    onCollapse={setCollapsed}
                    trigger={null}
                    width={220}
                    style={{
                        position: 'fixed',
                        left: 0,
                        top: 0,
                        bottom: 0,
                        zIndex: 100,
                        overflow: 'auto',
                    }}
                >
                    <div
                        style={{
                            height: 56,
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: collapsed ? 'center' : 'flex-start',
                            padding: collapsed ? 0 : '0 24px',
                            fontWeight: 700,
                            fontSize: collapsed ? 16 : 20,
                            letterSpacing: -0.5,
                            userSelect: 'none',
                        }}
                    >
                        {collapsed ? 'O' : 'Ockham'}
                    </div>
                    <Menu
                        mode="inline"
                        selectedKeys={[pathname]}
                        items={menuItems}
                        onClick={({ key }) => router.push(key)}
                        style={{ borderRight: 0 }}
                    />
                    <div
                        style={{
                            position: 'absolute',
                            bottom: 16,
                            left: 0,
                            right: 0,
                            padding: collapsed ? '0 8px' : '0 16px',
                            display: 'flex',
                            flexDirection: 'column',
                            gap: 4,
                        }}
                    >
                        <Button
                            type="text"
                            icon={themeMode === 'dark' ? <SunOutlined /> : <MoonOutlined />}
                            block
                            style={{ textAlign: 'left' }}
                            onClick={() => setThemeMode(themeMode === 'dark' ? 'light' : 'dark')}
                        >
                            {!collapsed && (themeMode === 'dark' ? 'Light' : 'Dark')}
                        </Button>
                        <Button
                            type="text"
                            icon={<SettingOutlined />}
                            block
                            style={{ textAlign: 'left' }}
                        >
                            {!collapsed && 'Settings'}
                        </Button>
                    </div>
                </Sider>
                <Layout
                    style={{
                        marginLeft: collapsed ? 80 : 220,
                        transition: 'margin-left 0.2s',
                        minHeight: '100vh',
                    }}
                >
                    <Header
                        style={{
                            padding: '0 24px',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'space-between',
                            height: 56,
                            lineHeight: '56px',
                            flexShrink: 0,
                        }}
                    >
                        <Button
                            type="text"
                            icon={collapsed ? <MenuUnfoldOutlined /> : <MenuFoldOutlined />}
                            onClick={() => setCollapsed(!collapsed)}
                        />
                        <Dropdown menu={{ items: userMenuItems }} trigger={['click']}>
                            <div style={{ cursor: 'pointer', display: 'flex', alignItems: 'center', gap: 8 }}>
                                <Avatar size="small" icon={<UserOutlined />} />
                                {!collapsed && (
                                    <Text style={{ fontSize: 13 }}>{session.user.name}</Text>
                                )}
                            </div>
                        </Dropdown>
                    </Header>
                    <Content style={{ padding: 24, overflow: 'auto' }}>
                        {children}
                    </Content>
                </Layout>
            </Layout>
        </ConfigProvider>
    )
}
